{"content": "@import "tailwindcss";

@theme {
  --color-primary: #7C3AED;
  --color-primary-foreground: #FFFFFF;
  --color-secondary: #1E1B4B;
  --color-secondary-foreground: #E2E8F0;
  --color-accent: #EC4899;
  --color-accent-foreground: #FFFFFF;
  --color-background: #0F0F1A;
  --color-surface: #1A1A2E;
  --color-surface-light: #252540;
  --color-foreground: #E2E8F0;
  --color-muted: #1A1A2E;
  --color-muted-foreground: #64748B;
  --color-border: #252540;
  --color-card: #1A1A2E;
  --color-card-foreground: #E2E8F0;
  --color-ring: #7C3AED;
  --color-input: #252540;
  --color-destructive: #EF4444;
  --color-destructive-foreground: #FFFFFF;
  --color-success: #10B981;
  --color-warning: #F59E0B;
}

body {
  background-color: var(--color-background);
  color: var(--color-foreground);
  font-family: 'Inter', sans-serif;
}

h1, h2, h3, h4 {
  font-family: 'Inter', sans-serif;
  font-weight: 700;
}

/* Scrollbar */
::-webkit-scrollbar { width: 6px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--color-border); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: var(--color-muted-foreground); }

/* Mobile tap improvements */
button, a, input, select, textarea {
  touch-action: manipulation;
  -webkit-tap-highlight-color: transparent;
}

/* Animations */
@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}
@keyframes pulse-subtle {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.7; }
}
.animate-fade-in-up { animation: fadeInUp 0.6s ease-out; }
.animate-float { animation: float 4s ease-in-out infinite; }

/* Shimmer */
@keyframes shimmer {
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}
.animate-shimmer {
  background: linear-gradient(90deg, var(--color-muted) 25%, var(--color-surface-light) 50%, var(--color-muted) 75%);
  background-size: 200% 100%;
  animation: shimmer 1.5s ease-in-out infinite;
}

/* Card hover */
.card-hover { transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1); }
.card-hover:hover { transform: translateY(-4px); box-shadow: 0 12px 24px rgba(124, 58, 237, 0.15); }

/* Fade slide up */
@keyframes slide-up {
  from { opacity: 0; transform: translateY(16px); }
  to { opacity: 1; transform: translateY(0); }
}
.animate-slide-up { animation: slide-up 0.3s ease-out; }

/* Safe area for notched devices */
@supports (padding-bottom: env(safe-area-inset-bottom)) {
  .safe-area-bottom { padding-bottom: env(safe-area-inset-bottom); }
}
