  useEffect(() => { if (catParam) setSelectedCat(catParam) }, [catParam])

  const filtered = selectedCat
    ? content.products.filter(p => p.category === selectedCat)
    : searchQuery
      ? content.products.filter(p => p.name.toLowerCase().includes(searchQuery.toLowerCase()))
      : content.products

  return (
    <div className="max-w-7xl mx-auto px-4 py-10">
