import { useState, useEffect } from "react"

const STORAGE_KEY = "fun4me_theme"

export function DarkModeToggle() {
  const [dark, setDark] = useState(true)

  useEffect(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY)
      if (saved === "light") {
        setDark(false)
        document.documentElement.classList.add("light")
      }
    } catch {}
  }, [])

  const toggle = () => {
    const next = !dark
    setDark(next)
    document.documentElement.classList.toggle("light", !next)
    try { localStorage.setItem(STORAGE_KEY, next ? "dark" : "light") } catch {}
  }

  return (
    <button onClick={toggle}
      className="flex h-9 w-9 items-center justify-center rounded-md text-muted-foreground transition-all hover:bg-surface-light"
      aria-label={dark ? "Modo claro" : "Modo oscuro"}>
      {dark ? (
        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="[REDACTED_PHONE]" fill="none" stroke="currentColor" strokeWidth="2">
