{"content": ""use client"
import { useParams } from "next/navigation"
import Link from "next/link"
import { useState, useEffect } from "react"
import content from "@/content/es.json"
import { useRecentlyViewed } from "@/lib/hooks"

function formatPrice(amount: number) { return `Gs. ${Math.round(amount).toLocaleString("es-PY")}` }
const WA_PHONE = "[REDACTED_PHONE]"

export default function ProductDetail() {
  const { slug } = useParams()
  const { addItem } = useRecentlyViewed()
  const [faqOpen, setFaqOpen] = useState<number | null>(null)
  const product = content.products.find((p: any) => p.slug === slug)

  useEffect(() => {
    if (product) addItem({ id: product.id, slug: product.slug, name: product.name, price: product.price })
  }, [product?.id])

  useEffect(() => {
    if (product) document.title = `${product.name} | ${content.siteName}`
    return () => { document.title = content.siteName }
  }, [product?.slug])

  if (!product) return (
    <div className="py-20 text-center">
      <h2 className="text-2xl font-bold mb-4">Producto no encontrado</h2>
      <Link href="/tienda" className="text-primary hover:underline">Volver a la tienda</Link>
    </div>
  )

  const waMsg = `https://wa.me/${WA_PHONE}?text=${encodeURIComponent(`¡Hola! Quiero: ${product.name} — ${formatPrice(product.price)}`)}`

  return (
    <div className="max-w-5xl mx-auto px-4 py-10">
      <Link href="/tienda" className="text-primary no-underline text-sm inline-block mb-6 hover:underline">← Volver a la tienda</Link>
      <div className="grid md:grid-cols-2 gap-10 items-start">
        <div className="bg-gradient-to-br from-surface-light to-surface rounded-2xl h-[400px] flex items-center justify-center relative">
          <span className="text-7xl opacity-10 select-none">✦</span>
          {product.new && <span className="absolute top-4 right-4 bg-accent text-accent-foreground text-xs font-bold px-3 py-1 rounded-full">Nuevo</span>}
        </div>
        <div>
          <h1 className="text-3xl font-bold mb-2">{product.name}</h1>
          {product.rating && (
            <div className="text-warning text-sm mb-3">
              {Array.from({ length: product.rating }).map((_, i) => <span key={i}>★</span>)}
              <span className="text-muted-foreground ml-2 text-xs">({product.reviews} reseñas)</span>
            </div>
          )}
          <p className="text-3xl font-bold text-primary mb-6">{formatPrice(product.price)}</p>
          <p className="text-muted-foreground leading-relaxed mb-6">{product.description}</p>
          <h3 className="font-semibold text-base mb-3">Características:</h3>
          <ul className="space-y-2 mb-8">
            {(product.features || []).map((f: string, i: number) => (
              <li key={i} className="flex items-center gap-2 text-muted-foreground text-sm"><span className="text-success">✓</span> {f}</li>
            ))}
          </ul>
          <a href={waMsg} target="_blank" rel="noopener noreferrer"
            className="inline-flex items-center justify-center gap-2 bg-[#25D366] text-white px-8 py-4 rounded-xl font-semibold no-underline text-lg hover:bg-[#20BD5A] transition-colors w-full">
            Consultar por WhatsApp
          </a>
        </div>
      </div>
      {product.faq && product.faq.length > 0 && (
        <div className="mt-12 max-w-3xl">
          <h2 className="text-2xl font-bold mb-6">Preguntas frecuentes</h2>
          <div className="space-y-2">
            {product.faq.map((item: any, i: number) => (
              <div key={i} className="rounded-xl border border-border bg-surface overflow-hidden">
                <button onClick={() => setFaqOpen(faqOpen === i ? null : i)}
                  className="w-full px-5 py-4 text-left text-foreground font-semibold text-sm cursor-pointer flex justify-between items-center gap-4 hover:bg-surface-light transition-colors">
                  <span>{item.q}</span>
                  <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="[REDACTED_PHONE]" fill="none" stroke="currentColor" strokeWidth="2"
                    className={`transition-transform shrink-0 ${faqOpen === i ? "rotate-180" : ""}`}>
                    <path d="m[REDACTED_PHONE]"/>
                  </svg>
                </button>
                {faqOpen === i && <div className="px-5 pb-4 text-muted-foreground text-sm">{item.a}</div>}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  )
}
