    for i, p in enumerate(products_raw if isinstance(products_raw, list) else []):
        price = p.get("price", 0)
        if isinstance(price, str):
            try: price = float(price.replace("Gs.", "").replace(".", "").replace(",", ".").strip())
            except: price = 0
        products.append({
            "id": p.get("id", i + 1),
            "slug": p.get("slug", p.get("name", "product-" + str(i)).lower().replace(" ", "-")),
            "name": p.get("name", ""),
