    contacto = o.get("contacto", o.get("contact", {}))
    if not contacto or isinstance(contacto, str): contacto = {"title": "Contacto", "subtitle": "Contactanos", "whatsapp": wa_phone}

    blog = o.get("blog", {"title": "Blog", "subtitle": "", "categories": [], "posts": []})
    if isinstance(blog, list): blog = {"title": "Blog", "subtitle": "", "categories": [], "posts": blog}
    if isinstance(blog, dict) and "posts" not in blog: blog["posts"] = []

    footer = o.get("footer", {"description": tagline, "columns": [{"title": "Enlaces", "links": [{"label": "Inicio", "href": ""}]}], "copyright": "(c) 2026 " + site_name})

    return {
        "siteName": o.get("siteName") or o.get("site", {}).get("name", site_name),
        "businessName": o.get("businessName") or o.get("site", {}).get("name", site_name),
        "tagline": tagline, "metaDescription": meta_desc, "navigation": nav, "home": home,
        "products": products, "categories": cats, "envio": o.get("envio", {"title": "Envio", "subtitle": "", "points": [], "cta": "Consultar"}),
        "faq": faq, "testimonials": o.get("testimonials", []), "contacto": contacto, "nosotros": nos,
        "promociones": o.get("promociones", {"title": "Promociones", "subtitle": "", "promotions": []}),
        "blog": blog, "footer": footer,
    }

